class InMemoryAuthRepository implements AuthRepository {
  AuthSession? _serverSession;

  @override
  Future<AuthSession> login({
    required String email,
    required String password,
  }) async {
    await Future<void>.delayed(const Duration(milliseconds: 500));

    if (email.isEmpty || password.isEmpty) {
      throw Exception('Email and password are required');
    }

    final session = AuthSession(
      user: AuthUser(
        id: 'user_${email.hashCode}',
        email: email,
        name: email.split('@').first,
        metadata: {
          'provider': 'password',
          'platformParity': 'enabled',
        },
      ),
      tokens: AuthTokens(
        accessToken: 'access_${DateTime.now().millisecondsSinceEpoch}',
        refreshToken: 'refresh_${DateTime.now().millisecondsSinceEpoch}',
        expiresAt: DateTime.now().add(const Duration(hours: 1)),
      ),
    );

    _serverSession = session;
    return session;
  }

  @override
  Future<void> logout(AuthSession? currentSession) async {
    await Future<void>.delayed(const Duration(milliseconds: 200));
    _serverSession = null;
  }

  @override
  Future<AuthSession> refreshSession(AuthSession currentSession) async {
    await Future<void>.delayed(const Duration(milliseconds: 300));

    final refreshToken = currentSession.tokens.refreshToken;
    if (refreshToken == null || refreshToken.isEmpty) {
      throw Exception('Refresh token missing');
    }

    final refreshed = currentSession.copyWith(
      tokens: currentSession.tokens.copyWith(
        accessToken: 'access_${DateTime.now().millisecondsSinceEpoch}',
        expiresAt: DateTime.now().add(const Duration(hours: 1)),
      ),
    );

    _serverSession = refreshed;
    return refreshed;
  }
